"""
Hello World HTTP handler — Python compiled to WASM via componentize-py.

Build (generates bindings then compiles):
    componentize-py -d wit -w proxy bindings .
    componentize-py -d wit -w proxy -p . componentize app -o hello-py-raw.wasm

Run:
    wasmtime serve hello-py-raw.wasm --addr 127.0.0.1:5032
"""

import json
import time

# Bindings are generated by `componentize-py bindings` into wit_world/.
# The build step runs this automatically before compilation.
from wit_world.imports import types as http
from wit_world.types import Ok


class IncomingHandler:
    def handle(self, request: http.IncomingRequest, response_out: http.ResponseOutparam) -> None:
        body = json.dumps(
            {
                "message": "Hello World",
                "timestamp": time.time(),
            }
        ).encode()

        headers = http.Fields.from_list([("content-type", b"application/json")])
        response = http.OutgoingResponse(headers)
        response.set_status_code(200)

        outgoing_body = response.body()
        stream = outgoing_body.write()
        stream.blocking_write_and_flush(body)
        del stream

        http.OutgoingBody.finish(outgoing_body, None)
        http.ResponseOutparam.set(response_out, Ok(response))
